<template>
<div class="app-shell"><aside class="sidebar card"><div><div class="eyebrow">Campus Repair Console</div><h2>{{ roleLabel(authState.user?.role) }}</h2><p class="subtle">{{ authState.user?.realName }} · {{ authState.user?.username }}</p></div><nav class="nav-list"><button v-for="t in tabs" :key="t.key" class="nav-item" :class="{active:activeTab===t.key}" @click="activeTab=t.key"><span>{{ t.icon }}</span>{{ t.label }}</button></nav><button class="btn btn-ghost" @click="openPasswordDialog">修改密码</button><button class="btn btn-ghost" @click="logout">退出登录</button></aside><main class="content-grid"><section class="hero card"><div><div class="eyebrow">Admin Hub</div><h1>管理员工作台</h1><p class="subtle">派单、人工确认、待分配、分类修正与规则配置闭环。</p></div></section><section class="card panel stack-lg"><div class="section-head"><h3>{{ currentTitle }}</h3><div class="cluster"><button class="btn btn-ghost" @click="loadAll">刷新</button><button v-if="activeTab==='dispatch'" class="btn btn-primary" @click="showPool=!showPool">{{ showPool?'收起维修池':'维修池' }}</button></div></div><div v-if="detail" class="detail-board"><div><span>工单号</span><strong>{{ detail.ticketNo }}</strong></div><div><span>状态</span><StatusPill :label="detail.status"/></div><div><span>位置</span><strong>{{ detail.locationText||'待解析' }}</strong></div><div><span>故障</span><strong>{{ detail.faultDesc||detail.rawText }}</strong></div><div><span>AI分类</span><strong>{{ categoryName(detail.categoryId) }}</strong></div><div><span>维修结果</span><strong>{{ detail.repairResult||'-' }}</strong></div><div><span>评价</span><strong>{{ detail.evaluationScore ? (detail.evaluationScore+'分 '+(detail.evaluationComment||'')) : '-' }}</strong></div></div><div v-if="detail?.llmTrace" class="trace-panel"><div class="section-head"><h4>智能解析追溯</h4><span class="subtle">可追溯的智能解析机制</span></div><div class="detail-board"><div><span>模型名称</span><strong>{{ detail.llmTrace.modelName||'-' }}</strong></div><div><span>Prompt版本</span><strong>{{ detail.llmTrace.promptVersion||'-' }}</strong></div><div><span>是否启用RAG</span><strong>{{ detail.llmTrace.ragEnabled?'是':'否' }}</strong></div><div><span>命中知识条数</span><strong>{{ detail.llmTrace.ragHitCount ?? 0 }}</strong></div><div><span>置信度</span><strong>{{ detail.llmTrace.confidence ?? '-' }}</strong></div><div><span>解析状态</span><strong>{{ detail.llmTrace.parseStatus||'-' }}</strong></div><div v-if="detail.llmTrace.failureReason"><span>失败原因</span><strong>{{ detail.llmTrace.failureReason }}</strong></div></div><label class="field"><span>原始模型返回内容</span><textarea readonly rows="4" :value="detail.llmTrace.rawResponse||'暂无原始返回'"/></label><label class="field"><span>解析日志</span><textarea readonly rows="4" :value="detail.llmTrace.normalizedResult||'暂无解析日志'"/></label></div><div v-if="activeTab==='dispatch'&&showPool" class="worker-pool"><div class="worker-pool__default" v-if="preferredWorkerId"><span>默认改派人</span><strong>{{ preferredWorkerName }}</strong></div><div class="worker-pool__grid"><article v-for="w in workers" :key="w.workerId" class="worker-card" :class="{'worker-card--selected':preferredWorkerId===w.workerId}"><strong>{{ w.workerName }}</strong><div class="worker-card__tags"><span>{{ w.skillTags }}</span><span>{{ w.serviceArea }}</span></div><div class="worker-card__metrics"><div><span>负载</span><strong>{{ w.currentLoad }}</strong></div><div><span>接单率</span><strong>{{ pct(w.acceptRate) }}</strong></div></div><button class="btn btn-ghost" @click="preferredWorkerId=preferredWorkerId===w.workerId?null:w.workerId">{{ preferredWorkerId===w.workerId?'取消默认改派人':'设为默认改派人' }}</button></article></div></div><div v-if="showTable" class="table-wrap"><table><thead><tr><th>工单号</th><th>状态</th><th>位置</th><th>故障</th><th>AI分类</th><th v-if="activeTab==='dispatch'">维修人</th><th v-if="activeTab==='categoryFix'">分类修正</th><th>操作</th></tr></thead><tbody><tr v-for="it in tableData" :key="it.ticketId"><td>{{ it.ticketNo }}</td><td><StatusPill :label="it.status"/></td><td>{{ it.locationText||'待解析' }}</td><td>{{ it.faultDesc||'待解析' }}</td><td>{{ categoryName(it.categoryId) }}</td><td v-if="activeTab==='dispatch'">{{ workerName(it.currentWorkerId) }}</td><td v-if="activeTab==='categoryFix'"><select v-model="categoryFixMap[it.ticketId]"><option value="">请选择</option><option v-for="c in categories" :key="c.categoryId" :value="c.categoryId">{{ c.categoryName }}</option></select></td><td><div class="action-grid"><button class="btn btn-ghost" @click="viewTicket(it.ticketId)">详情</button><button v-if="activeTab==='dispatch'&&it.status==='待受理'" class="btn btn-primary" @click="parseTicket(it.ticketId)">解析</button><button v-if="(activeTab==='dispatch'||activeTab==='pendingPool')&&['已解析','待分配'].includes(it.status)" class="btn btn-primary" @click="autoDispatch(it.ticketId)">自动派单</button><button v-if="(activeTab==='dispatch'||activeTab==='pendingPool')&&['已解析','待分配','已派单'].includes(it.status)" class="btn btn-ghost" @click="openManualDispatch(it.ticketId)">改派</button><button v-if="activeTab==='categoryFix'" class="btn btn-primary" @click="correctCategory(it.ticketId)">提交修正</button></div></td></tr></tbody></table></div><div v-if="activeTab==='reviewQueue'" class="table-wrap"><table><thead><tr><th>工单号</th><th>原始文本</th><th>原因</th><th>状态</th><th>操作</th></tr></thead><tbody><tr v-for="q in reviewQueue" :key="q.id"><td>{{ q.ticketNo }}</td><td>{{ q.rawText }}</td><td>{{ q.reason }}</td><td><StatusPill :label="q.queueStatus"/></td><td><div class="action-grid"><button class="btn btn-primary" @click="openConfirmQueue(q)">人工补录</button></div></td></tr></tbody></table></div><div v-if="activeTab==='rules'" class="stack-lg"><div class="rule-hero"><div><div class="eyebrow">Dispatch Rule</div><h4>派单权重配置</h4><p class="subtle">仅展示当前可编辑的派单权重，并基于实际配置进行保存或重算。</p></div></div><div class="rule-grid"><article v-for="item in weightItems" :key="item.key" class="rule-card"><div class="rule-card__head"><strong>{{ item.label }}</strong><span>{{ (item.value*100).toFixed(0) }}%</span></div><input v-model.number="ruleForm[item.key]" type="range" min="0" max="1" step="0.01"/><input v-model.number="ruleForm[item.key]" type="number" min="0" max="1" step="0.01"/></article></div><div class="cluster"><span class="subtle">建议保持总和为 1。技能、区域、负载决定基础匹配；绩效与紧急度用于精细调度。</span><button class="btn btn-primary" @click="saveWeights">保存</button><button class="btn btn-ghost" @click="recalculate">基于反馈重算</button></div></div><div v-if="activeTab==='stats'" class="stats-visual"><div class="stats-kpi-grid"><article class="kpi-card"><span>派单总量</span><strong>{{ latestSnapshot?.dispatchCount ?? 0 }}</strong><small>统计窗口总派单次数</small></article><article class="kpi-card"><span>改派率</span><strong>{{ latestSnapshot ? pctNum(latestSnapshot.reassignRate) : '-' }}</strong><small>人工改派占比</small></article><article class="kpi-card"><span>拒单率</span><strong>{{ latestSnapshot ? pctNum(latestSnapshot.rejectRate) : '-' }}</strong><small>维修人员拒单占比</small></article><article class="kpi-card"><span>超时率</span><strong>{{ latestSnapshot ? pctNum(latestSnapshot.timeoutRate) : '-' }}</strong><small>超 24h 完工占比</small></article><article class="kpi-card"><span>平均完工</span><strong>{{ latestSnapshot?.avgCompleteHours ?? '-' }}h</strong><small>统计窗口平均完工时长</small></article></div><div class="dashboard-columns"><div class="mini-panel"><h4>分类分布</h4><div class="bar-list"><div v-for="i in categoryStats" :key="i.name" class="bar-item"><div class="bar-item__head"><span>{{ i.name }}</span><strong>{{ i.count }}</strong></div><div class="bar-track"><div class="bar-fill" :style="{width:barWidth(i.count,categoryMax)}"></div></div></div></div></div><div class="mini-panel"><h4>维修负载</h4><div class="bar-list"><div v-for="i in workerLoad" :key="i.workerId" class="bar-item"><div class="bar-item__head"><span>{{ i.workerName }}</span><strong>{{ i.count }}</strong></div><div class="bar-track bar-track--warm"><div class="bar-fill bar-fill--warm" :style="{width:barWidth(i.count,workerMax)}"></div></div></div></div></div><div class="mini-panel"><h4>权重结构</h4><div class="weight-ring-list"><div v-for="item in weightItems" :key="item.key" class="weight-line"><span>{{ item.label }}</span><div class="bar-track"><div class="bar-fill bar-fill--cyan" :style="{width:(item.value*100)+'%'}"></div></div><strong>{{ (item.value*100).toFixed(0) }}%</strong></div></div></div></div></div><div v-if="activeTab==='account'" class="stack-lg"><div class="rule-hero"><div><div class="eyebrow">Account</div><h4>维修人员账号发放与密码重置</h4><p class="subtle">维修人员账号由管理员创建，初始密码线下告知；用户忘记密码且手机号不可用时，可由管理员重置。</p></div></div><div class="profile-grid"><label><span>用户名</span><input v-model.trim="workerForm.username" placeholder="例如 worker006"/></label><label><span>初始密码</span><input v-model.trim="workerForm.password" type="password" placeholder="至少6位"/></label><label><span>姓名</span><input v-model.trim="workerForm.realName" placeholder="维修人员姓名"/></label><label><span>手机号</span><input v-model.trim="workerForm.phone" placeholder="用于找回密码，必填"/></label><label><span>技能标签</span><input v-model.trim="workerForm.skillTags" placeholder="NETWORK,WATER_ELECTRIC"/></label><label><span>服务区域</span><input v-model.trim="workerForm.serviceArea" placeholder="宿舍片区,教学楼片区"/></label></div><div class="cluster"><button class="btn btn-primary" @click="createWorkerAccount">创建维修人员账号</button><button class="btn btn-ghost" @click="resetUserPassword">重置用户密码</button></div><div class="table-wrap"><table><thead><tr><th>用户ID</th><th>维修员ID</th><th>姓名</th><th>技能</th><th>区域</th><th>负载</th></tr></thead><tbody><tr v-for="w in workers" :key="w.workerId"><td>{{ w.userId }}</td><td>{{ w.workerId }}</td><td>{{ w.workerName }}</td><td>{{ w.skillTags }}</td><td>{{ w.serviceArea }}</td><td>{{ w.currentLoad }}</td></tr></tbody></table></div></div><p v-if="fb.global" class="feedback feedback-success">{{ fb.global }}</p><p v-if="fb.error" class="feedback feedback-error">{{ fb.error }}</p></section><div v-if="modal.type" class="modal-backdrop" @click.self="closeModal"><section class="modal-card card"><div class="section-head"><h3>{{ modalTitle }}</h3><button class="btn btn-ghost" @click="closeModal">关闭</button></div><form v-if="modal.type==='manualDispatch'" class="stack-lg" @submit.prevent="submitManualDispatch"><label class="field"><span>选择维修人员</span><select v-model="manualDispatchForm.workerId"><option v-for="w in workers" :key="w.workerId" :value="w.workerId">{{ w.workerName }} · {{ w.skillTags }} · 负载{{ w.currentLoad }}</option></select></label><label class="field"><span>改派原因</span><textarea v-model.trim="manualDispatchForm.reason" rows="3" placeholder="请输入人工改派原因"/></label><button class="btn btn-primary" type="submit">确认改派</button></form><form v-if="modal.type==='manualConfirm'" class="stack-lg" @submit.prevent="submitConfirmQueue"><label class="field"><span>位置</span><input v-model.trim="manualConfirmForm.locationText"/></label><label class="field"><span>故障描述</span><textarea v-model.trim="manualConfirmForm.faultDesc" rows="3"/></label><label class="field"><span>紧急度</span><select v-model="manualConfirmForm.urgencyLevel"><option value="LOW">LOW</option><option value="MEDIUM">MEDIUM</option><option value="HIGH">HIGH</option></select></label><label class="field"><span>分类</span><select v-model="manualConfirmForm.categoryId"><option v-for="c in categories" :key="c.categoryId" :value="c.categoryId">{{ c.categoryName }}</option></select></label><button class="btn btn-primary" type="submit">提交人工确认</button></form></section></div></main></div>
</template>
<script setup>
import {computed,onMounted,reactive,ref} from 'vue'
import {useRouter} from 'vue-router'
import http,{unwrap} from '../api'
import {authState,clearAuth} from '../store/auth'
import {roleLabel} from '../utils'
import StatusPill from './StatusPill.vue'
const router=useRouter(),activeTab=ref('dispatch'),tickets=ref([]),pendingPool=ref([]),workers=ref([]),reviewQueue=ref([]),categories=ref([]),detail=ref(null),overview=ref(null),categoryStats=ref([]),workerLoad=ref([]),showPool=ref(false),preferredWorkerId=ref(null)
const manualConfirmDraft=reactive({locationText:'',faultDesc:'',urgencyLevel:'MEDIUM',categoryId:''})
const modal=reactive({type:'',ticketId:null,queueId:null})
const manualDispatchForm=reactive({workerId:'',reason:'管理员根据区域和技能人工改派'})
const manualConfirmForm=reactive({locationText:'',faultDesc:'',urgencyLevel:'MEDIUM',categoryId:''})
const tabs=[{key:'dispatch',label:'派单监控',icon:'◎'},{key:'pendingPool',label:'待分配池',icon:'◍'},{key:'reviewQueue',label:'人工确认',icon:'◌'},{key:'categoryFix',label:'分类修正',icon:'◫'},{key:'account',label:'账号管理',icon:'◇'},{key:'rules',label:'规则配置',icon:'⚙'},{key:'stats',label:'统计看板',icon:'▣'}]
const fb=reactive({global:'',error:''}),categoryFixMap=reactive({}),ruleForm=reactive({weightSkill:.35,weightArea:.2,weightLoad:.2,weightPerf:.1,weightUrgency:.15}),workerForm=reactive({username:'',password:'123456',realName:'',phone:'',skillTags:'NETWORK,WATER_ELECTRIC',serviceArea:'宿舍片区,教学楼片区'})
const currentTitle=computed(()=>tabs.find(i=>i.key===activeTab.value)?.label||''),modalTitle=computed(()=>modal.type==='manualDispatch'?'人工改派':modal.type==='manualConfirm'?'人工确认补录':''),tableData=computed(()=>activeTab.value==='pendingPool'?pendingPool.value:tickets.value),showTable=computed(()=>['dispatch','pendingPool','categoryFix'].includes(activeTab.value)),preferredWorkerName=computed(()=>workers.value.find(i=>i.workerId===preferredWorkerId.value)?.workerName||`#${preferredWorkerId.value}`),latestSnapshot=computed(()=>overview.value?.latestSnapshot||null),weightItems=computed(()=>[{label:'技能匹配',key:'weightSkill',value:Number(ruleForm.weightSkill||0)},{label:'服务区域',key:'weightArea',value:Number(ruleForm.weightArea||0)},{label:'任务负载',key:'weightLoad',value:Number(ruleForm.weightLoad||0)},{label:'历史绩效',key:'weightPerf',value:Number(ruleForm.weightPerf||0)},{label:'紧急程度',key:'weightUrgency',value:Number(ruleForm.weightUrgency||0)}]),categoryMax=computed(()=>Math.max(1,...categoryStats.value.map(i=>Number(i.count)||0))),workerMax=computed(()=>Math.max(1,...workerLoad.value.map(i=>Number(i.count)||0)))
const reset=()=>{fb.global='';fb.error=''},closeModal=()=>{modal.type='';modal.ticketId=null;modal.queueId=null},logout=()=>{clearAuth();router.push('/login')},pct=v=>v==null?'-':`${Math.round(Number(v)*100)}%`,pctNum=v=>`${Math.round(Number(v||0)*100)}%`,workerName=id=>workers.value.find(i=>i.workerId===id)?.workerName||(id?`#${id}`:'未指派'),categoryName=id=>categories.value.find(i=>i.categoryId===id)?.categoryName||(id?`#${id}`:'未分类'),barWidth=(count,max)=>`${Math.max(8,Math.round((Number(count||0)/Math.max(1,max))*100))}%`
async function run(task,msg=''){reset();try{await task();if(msg)fb.global=msg}catch(e){fb.error=e.message||'操作失败'}}
async function openPasswordDialog(){const oldPassword=window.prompt('请输入原密码');if(oldPassword===null)return;const newPassword=window.prompt('请输入新密码（至少6位）');if(newPassword===null)return;const confirmPassword=window.prompt('请再次输入新密码');if(confirmPassword===null)return;if(newPassword!==confirmPassword){fb.error='两次输入的新密码不一致';return}await run(async()=>{await http.post('/auth/password',{oldPassword,newPassword});clearAuth();router.push('/login')},'密码修改成功，请重新登录')}
async function createWorkerAccount(){await run(async()=>{const d=unwrap(await http.post('/admin/workers',{...workerForm}));workerForm.username='';workerForm.password='123456';workerForm.realName='';workerForm.phone='';await loadAll();fb.global=`维修人员账号已创建：${d.username}，请线下告知初始密码`},'')}
async function resetUserPassword(){const userId=window.prompt('请输入需要重置密码的用户ID');if(!userId)return;const newPassword=window.prompt('请输入新密码（至少6位）','123456');if(!newPassword)return;await run(async()=>{await http.post('/admin/workers/reset-password',{userId:Number(userId),newPassword})},'密码已重置，请线下告知用户')}
async function loadAll(){tickets.value=unwrap(await http.get('/admin/tickets?page=1&size=50')).records||[];workers.value=unwrap(await http.get('/admin/workers'));categories.value=unwrap(await http.get('/admin/categories'));await loadPendingPool();await loadRules()}
async function loadPendingPool(){pendingPool.value=unwrap(await http.get(`/admin/tickets?page=1&size=20&status=${encodeURIComponent('待分配')}`)).records||[]}
async function loadReviewQueue(){reviewQueue.value=unwrap(await http.get('/admin/llm/review-queue?page=1&size=20')).records||[]}
async function loadRules(){overview.value=unwrap(await http.get('/admin/dispatch-feedback'));categoryStats.value=unwrap(await http.get('/admin/stats/category-distribution'));workerLoad.value=unwrap(await http.get('/admin/stats/worker-load'));const activeWeight=overview.value?.activeWeight;if(activeWeight){ruleForm.weightSkill=Number(activeWeight.weightSkill??0);ruleForm.weightArea=Number(activeWeight.weightArea??0);ruleForm.weightLoad=Number(activeWeight.weightLoad??0);ruleForm.weightPerf=Number(activeWeight.weightPerf??0);ruleForm.weightUrgency=Number(activeWeight.weightUrgency??0)}}
async function viewTicket(id){await run(async()=>{detail.value=unwrap(await http.get(`/tickets/${id}`))})}
async function parseTicket(id){await run(async()=>{await http.post('/llm/parse',{ticketId:id});await loadAll();await loadReviewQueue();await viewTicket(id)},'LLM解析完成')}
async function autoDispatch(id){await run(async()=>{await http.post(`/tickets/${id}/dispatch/auto`);await loadAll();await viewTicket(id)},'自动派单已执行')}
async function legacyManualDispatch(id){const txt=workers.value.map(i=>`${i.workerId}:${i.workerName}`).join('\n');const v=window.prompt(`输入 workerId:\n${txt}`,preferredWorkerId.value||workers.value[0]?.workerId||'');if(!v)return;await run(async()=>{await http.post(`/tickets/${id}/dispatch/manual`,{workerId:Number(v),reason:'管理员人工改派'});preferredWorkerId.value=Number(v);await loadAll();await viewTicket(id)},'人工改派成功')}
async function legacyConfirmQueue(q){manualConfirmDraft.locationText=q.rawText||'';manualConfirmDraft.faultDesc='';manualConfirmDraft.urgencyLevel='MEDIUM';manualConfirmDraft.categoryId=categories.value[0]?.categoryId||'';const locationText=window.prompt('请输入位置',manualConfirmDraft.locationText);if(locationText===null)return;const faultDesc=window.prompt('请输入故障描述',manualConfirmDraft.faultDesc||q.rawText||'');if(faultDesc===null)return;const urgencyLevel=window.prompt('请输入紧急度（LOW/MEDIUM/HIGH）',manualConfirmDraft.urgencyLevel);if(urgencyLevel===null)return;const cid=window.prompt(`输入分类ID:\n${categories.value.map(i=>`${i.categoryId}:${i.categoryName}`).join('\n')}`,manualConfirmDraft.categoryId||'');if(cid===null)return;await run(async()=>{await http.post(`/admin/llm/review-queue/${q.id}/confirm`,{locationText:String(locationText).trim(),faultDesc:String(faultDesc).trim(),urgencyLevel:String(urgencyLevel).trim().toUpperCase(),categoryId:Number(cid)});await loadAll();await loadReviewQueue()},'人工确认已完成')}
async function openManualDispatch(id){modal.ticketId=id;manualDispatchForm.workerId=preferredWorkerId.value||workers.value[0]?.workerId||'';manualDispatchForm.reason='管理员根据区域和技能人工改派';modal.type='manualDispatch'}
async function submitManualDispatch(){if(!manualDispatchForm.workerId)return fb.error='请选择维修人员';await run(async()=>{await http.post(`/tickets/${modal.ticketId}/dispatch/manual`,{workerId:Number(manualDispatchForm.workerId),reason:manualDispatchForm.reason||'管理员人工改派'});preferredWorkerId.value=Number(manualDispatchForm.workerId);const id=modal.ticketId;closeModal();await loadAll();await viewTicket(id)},'人工改派成功')}
async function openConfirmQueue(q){modal.queueId=q.id;manualConfirmForm.locationText='';manualConfirmForm.faultDesc=q.rawText||'';manualConfirmForm.urgencyLevel='MEDIUM';manualConfirmForm.categoryId=categories.value[0]?.categoryId||'';modal.type='manualConfirm'}
async function submitConfirmQueue(){if(!manualConfirmForm.locationText||!manualConfirmForm.faultDesc||!manualConfirmForm.categoryId)return fb.error='请完整填写人工确认信息';await run(async()=>{await http.post(`/admin/llm/review-queue/${modal.queueId}/confirm`,{locationText:manualConfirmForm.locationText,faultDesc:manualConfirmForm.faultDesc,urgencyLevel:manualConfirmForm.urgencyLevel,categoryId:Number(manualConfirmForm.categoryId)});closeModal();await loadAll();await loadReviewQueue()},'人工确认已完成')}
async function correctCategory(id){if(!categoryFixMap[id])return fb.error='请选择分类';await run(async()=>{await http.post(`/admin/tickets/${id}/category`,{categoryId:Number(categoryFixMap[id]),reason:'管理员前端修正'});await loadAll();await viewTicket(id)},'分类修正已提交')}
async function saveWeights(){const sum=Number(ruleForm.weightSkill||0)+Number(ruleForm.weightArea||0)+Number(ruleForm.weightLoad||0)+Number(ruleForm.weightPerf||0)+Number(ruleForm.weightUrgency||0);if(Math.abs(sum-1)>0.001)return fb.error='权重之和必须为1';await run(async()=>{overview.value=unwrap(await http.post('/admin/dispatch-feedback/weights',{...ruleForm}));await loadRules()},'规则权重已更新')}
async function recalculate(){await run(async()=>{overview.value=unwrap(await http.post('/admin/dispatch-feedback/recalculate'));await loadRules()},'派单反馈权重已重算')}
onMounted(async()=>{await loadAll();await loadReviewQueue()})
</script>
